parameters.jsCode:
let json = $('If All Finished').first().json;
if (!json.finishedSet) json.finishedSet = [];
if (!json.outputs || Array.isArray(json.outputs)) {
  json.outputs = { "transcript-agent": {}, "peer-agent": {} };
}

let body = $('Webhook Callback Wait').item.json.body;
let finishedItemId = body.finishedItemId;
let transcriptOutput = body.transcriptOutput;
let peerOutput = body.peerOutput;

if (!json.finishedSet.includes(finishedItemId)) {
  json.finishedSet.push(finishedItemId);
}

if (finishedItemId && transcriptOutput !== undefined) {
  json.outputs["transcript-agent"] = transcriptOutput;
}

if (finishedItemId && peerOutput !== undefined) {
  json.outputs["peer-agent"] = peerOutput;
}

return [json];

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "ticker": { "type": "string" },
    "quarter": { "type": "string" },
    "executive_summary": {
      "type": "object",
      "properties": {
        "beat_miss": { "type": "string", "enum": ["beat", "miss", "inline"] },
        "metrics": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "label": { "type": "string" },
              "value": { "type": "string" },
              "yoy_change": { "type": "number" }
            },
            "required": ["label", "value", "yoy_change"]
          }
        },
        "headline_takeaway": { "type": "string" },
        "key_drivers": {
          "type": "array",
          "items": { "type": "string" }
        },
        "primary_driver": { "type": "string" },
        "forward_guidance": { "type": "string" }
      },
      "required": ["beat_miss", "metrics", "headline_takeaway", "key_drivers", "primary_driver", "forward_guidance"]
    },
    "key_insights": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "signal": { "type": "string", "enum": ["bullish", "bearish", "neutral"] },
          "title": { "type": "string" },
          "detail": { "type": "string" }
        },
        "required": ["signal", "title", "detail"]
      }
    },
    "delta_vs_last_quarter": {
      "type": "object",
      "properties": {
        "comparison": { "type": "string" },
        "changes": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "type": { "type": "string", "enum": ["new", "tone_shift", "metric_change", "dropped", "unchanged"] },
              "title": { "type": "string" },
              "detail": { "type": "string" }
            },
            "required": ["type", "title", "detail"]
          }
        }
      },
      "required": ["comparison", "changes"]
    },
    "industry_trends": {
      "type": "object",
      "properties": {
        "themes": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "category": { "type": "string", "enum": ["dominant", "emerging", "persistent"] },
              "title": { "type": "string" },
              "detail": { "type": "string" },
              "mentioned_by": {
                "type": "array",
                "items": { "type": "string" }
              }
            },
            "required": ["category", "title", "detail", "mentioned_by"]
          }
        },
        "sources": {
          "type": "array",
          "items": { "type": "string" }
        }
      },
      "required": ["themes", "sources"]
    },
    "competitive_landscape": {
      "type": "object",
      "properties": {
        "companies": {
          "type": "array",
          "description": "Column headers: [target ticker, peer1, peer2, ...]. Same order used in all positions arrays.",
          "items": { "type": "string" }
        },
        "offerings": {
          "type": "array",
          "description": "Each row is a segment that at least two companies share. Only include segments that appear in multiple companies' income statements.",
          "items": {
            "type": "object",
            "properties": {
              "category": {
                "type": "string",
                "description": "The common segment mapped across companies, e.g. 'Cloud Services', 'Advertising Revenue'"
              },
              "positions": {
                "type": "array",
                "description": "One entry per company (same order as companies array). Sourced from income statement data retrieved via the Financial Statement API.",
                "items": {
                  "type": "object",
                  "properties": {
                    "segment_name": {
                      "type": "string",
                      "description": "The exact segment label as it appears in that company's income statement, e.g. 'Amazon Web Services', 'Google Cloud'"
                    },
                    "revenue": {
                      "type": "string",
                      "description": "Most recent fiscal year revenue for this segment, e.g. '$105.5B'"
                    },
                    "revenue_prior_year": {
                      "type": "string",
                      "description": "Prior fiscal year revenue for this segment, e.g. '$90.8B'"
                    },
                    "yoy_growth": {
                      "type": "number",
                      "description": "Year-over-year growth rate calculated from the two fiscal years, e.g. '+16.2%'"
                    },
                    "has_segment": {
                      "type": "boolean",
                      "description": "Whether this company reports a comparable segment. If false, all other fields should be 'N/A'."
                    }
                  },
                  "required": ["segment_name", "revenue", "revenue_prior_year", "yoy_growth", "has_segment"]
                }
              }
            },
            "required": ["category", "positions"]
          }
        },
        "data_source": {
          "type": "string",
          "description": "The URL pattern used to retrieve income statements",
          "const": "https://raw.githubusercontent.com/gselez6761/agentic-ai-challenge-data/main/data/income_statements/{TICKER}/income_statement_{TICKER}.json"
        }
      },
      "required": ["companies", "offerings", "data_source"]
    }
  },
  "required": ["ticker", "quarter", "executive_summary", "key_insights", "delta_vs_last_quarter", "industry_trends", "competitive_landscape"]
}
